<li>\u7F16\u5199java\u4EE3\u7801\uFF0C\u6D4B\u8BD5\u901A\u8FC7\u540E\u518D\u8F6C\u4E3Asmali\uFF0C\u52A0\u5165dex\u4E2D</li>
